/* ============================================================
   Murallas · Consultoría SARLAFT
   Monochrome, minimalist, high-contrast theme
   ============================================================ */

:root {
  --black: #0a0a0a;
  --ink: #111111;
  --gray-900: #1a1a1a;
  --gray-600: #6b6b6b;
  --gray-400: #9b9b9b;
  --gray-200: #e6e6e6;
  --gray-100: #f4f4f2;
  --white: #ffffff;
  --line: #e7e7e3;
  --max: 1200px;
  --pad: clamp(1.25rem, 4vw, 3rem);
  --sans: "Inter", system-ui, -apple-system, "Segoe UI", sans-serif;
  --serif: "Fraunces", Georgia, "Times New Roman", serif;
  --ease: cubic-bezier(0.22, 1, 0.36, 1);
}

* { box-sizing: border-box; margin: 0; padding: 0; }

html { scroll-behavior: smooth; -webkit-text-size-adjust: 100%; }

body {
  font-family: var(--sans);
  color: var(--ink);
  background: var(--white);
  line-height: 1.6;
  font-weight: 400;
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
}

img { max-width: 100%; display: block; }
a { color: inherit; text-decoration: none; }
ul { list-style: none; }

.container {
  width: 100%;
  max-width: var(--max);
  margin-inline: auto;
  padding-inline: var(--pad);
}

/* ---------- Typography helpers ---------- */
.eyebrow {
  font-size: 0.78rem;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: var(--gray-600);
  font-weight: 500;
}

.serif-italic { font-family: var(--serif); font-style: italic; font-weight: 400; }

.section-title {
  font-size: clamp(1.9rem, 4.5vw, 3.1rem);
  line-height: 1.08;
  letter-spacing: -0.02em;
  font-weight: 600;
  color: var(--black);
}

.section-lead {
  margin-top: 1.1rem;
  max-width: 56ch;
  color: var(--gray-600);
  font-size: 1.05rem;
}

.section { padding-block: clamp(4rem, 9vw, 7.5rem); }

.section-head { max-width: 760px; margin-bottom: clamp(2.5rem, 5vw, 4rem); }

/* ---------- Buttons ---------- */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  padding: 0.95rem 1.6rem;
  font-size: 0.95rem;
  font-weight: 500;
  letter-spacing: 0.01em;
  border: 1px solid var(--black);
  border-radius: 999px;
  cursor: pointer;
  transition: background 0.3s var(--ease), color 0.3s var(--ease),
    transform 0.3s var(--ease), border-color 0.3s var(--ease);
}
.btn:hover { transform: translateY(-2px); }
.btn-dark { background: var(--black); color: var(--white); }
.btn-dark:hover { background: var(--gray-900); }
.btn-ghost { background: transparent; color: var(--black); }
.btn-ghost:hover { background: var(--black); color: var(--white); }
.btn-light { background: var(--white); color: var(--black); border-color: var(--white); }
.btn-light:hover { background: transparent; color: var(--white); border-color: var(--white); }
.btn-block { width: 100%; }

/* ---------- Header ---------- */
.site-header {
  position: sticky;
  top: 0;
  z-index: 50;
  background: rgba(255, 255, 255, 0.82);
  backdrop-filter: saturate(180%) blur(14px);
  border-bottom: 1px solid var(--line);
}
.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 76px;
}
.brand { display: flex; flex-direction: column; line-height: 1.05; }
.brand-mark {
  font-weight: 700;
  letter-spacing: 0.16em;
  font-size: 1.15rem;
  color: var(--black);
}
.brand-sub {
  font-size: 0.66rem;
  letter-spacing: 0.24em;
  text-transform: uppercase;
  color: var(--gray-600);
}
.nav { display: flex; gap: 2.2rem; }
.nav a {
  font-size: 0.95rem;
  color: var(--gray-600);
  font-weight: 500;
  transition: color 0.25s var(--ease);
  position: relative;
}
.nav a:hover { color: var(--black); }
.nav-cta { padding: 0.6rem 1.2rem; font-size: 0.88rem; }

/* ---------- Mobile nav toggle ---------- */
.nav-toggle {
  display: none;
  flex-direction: column;
  gap: 5px;
  background: none;
  border: none;
  cursor: pointer;
  padding: 6px;
}
.nav-toggle span {
  width: 24px; height: 2px; background: var(--black);
  transition: transform 0.3s var(--ease), opacity 0.3s var(--ease);
}
